    public Set<LnedefRegBv> getRegimes(RekenBvKey bvKey, LocalDate rekenDatum) {
        Set<LnedefRegBv> regimes = REGIME_TO_BV_KEY_MAP.inverse().get(bvKey);
        if (rekenDatum.compareTo(START_OVERWERK_GEWONE_BEZOLDIGING) < 0 && bvKey == BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY) {
            regimes = new HashSet<>(regimes);
            regimes.add(LnedefRegBv.VD_BV_10_OVERWERK);
            regimes = ImmutableSet.copyOf(regimes);
        } else if (bvKey == BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY && rekenDatum.compareTo(START_OVERWERK_GEWONE_BEZOLDIGING) < 0) {
            regimes = new HashSet<>(regimes);
            regimes.remove(LnedefRegBv.VD_BV_10_OVERWERK);
            regimes = ImmutableSet.copyOf(regimes);
        }
        return regimes;
    }

    public static boolean isRegimeBv(LnedefRegBv regimeBv, LocalDate rekenDatum, ContextKey bvKey) {
        if (regimeBv == LnedefRegBv.VD_BV_10_OVERWERK) {
            return (bvKey == BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY && rekenDatum.compareTo(START_OVERWERK_GEWONE_BEZOLDIGING) < 0) || (
                    (bvKey == BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY || bvKey == VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY ||
                            bvKey == VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY)
                            && rekenDatum.compareTo(START_OVERWERK_GEWONE_BEZOLDIGING) >= 0);
        } else {
            return isRegimeBv(regimeBv, bvKey);
        }
    }

    private static boolean isRegimeBv(LnedefRegBv regimeBv, ContextKey bvKey) {
        Set<RekenBvKey> keySet = REGIME_TO_BV_KEY_MAP.get(regimeBv);
        return keySet.contains(bvKey);
    }

    public static boolean isRegimeAchterstal(LnedefRegBv regimeBv) {
        return BvTools.isRegimeBv(regimeBv, BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY) || BvTools
                .isRegimeBv(regimeBv, BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY) || BvTools.isRegimeBv(regimeBv, BEDRIJFSVOORHEFFING_VAKANTIEGELD_KEY);
    }

    public static Set<RekenBvKey> regimeToBvKey(LnedefRegBv regimeBv, LocalDate rekenDatum) {
        Set<RekenBvKey> bvKeys;
        if (regimeBv == LnedefRegBv.VD_BV_10_OVERWERK) {
            if (rekenDatum.compareTo(START_OVERWERK_GEWONE_BEZOLDIGING) < 0) {
                bvKeys = Sets.immutableEnumSet(BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY);
            } else {
                bvKeys = Sets.immutableEnumSet(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY,
                        VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY);
            }
        } else {
            bvKeys = REGIME_TO_BV_KEY_MAP.get(regimeBv);

        }
        return bvKeys;
    }

    private static final Map<LnedefRegBv, RekenBvKey> ACHTERSTAL_REGIME_TO_BV_KEY_MAP = new HashMap<>();

    static {

        LnedefRegBv[] regimesGewoonBvAst =
