                        LnedefRegBv.VD_BV_10_VVAA_GB, LnedefRegBv.VD_BV_10_VVAA_GB_AFTROK_SOC_INH, LnedefRegBv.VD_BV_10_AWWV_gb,
                        LnedefRegBv.VD_BV_10_VVAA_GB_BRUTO, LnedefRegBv.VD_BV_10_OVERWERK, LnedefRegBv.VD_BV_10_UKZI_GB, LnedefRegBv.VD_BV_10_UKAG_GB,
                        LnedefRegBv.VD_BV_11_PENS_GB, LnedefRegBv.VD_BV_14_B_AU_EXC, LnedefRegBv.VD_BV_16_RENTE_EXC, LnedefRegBv.VD_BV_10_MOB_VERG_INLV_WAGEN,
                        LnedefRegBv.VD_BV_20_VEREFFENAAR, LnedefRegBv.VD_BV_17_BRUG_PENS, LnedefRegBv.VD_BV_10_VVAA_EXC};

        for (LnedefRegBv regimeBv : regimesGewoonBvAst) {
            ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(regimeBv, BEDRIJFSVOORHEFFING_ACHTERSTAL_KEY);
        }

        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_10_BZ___VB, BEDRIJFSVOORHEFFING_ACHTERSTAL_VRIJWILLIGE_BRANDWEER_KEY);

        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_14_TAO, BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY);

        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_10_UKAG_BV, BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_PREMIE_KEY);

        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_12_VVI__BV, BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_ZIEKTE_KEY);


        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_10_FTSW_EXC, BEDRIJFSVOORHEFFING_ACHTERSTAL_FIETS_VERGOEDING_KEY);

        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_10_BZ___TV, BEDRIJFSVOORHEFFING_ACHTERSTAL_TOEVALLIGE_VERGOEDINGEN_KEY);
        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_30_BBI__TV, BEDRIJFSVOORHEFFING_ACHTERSTAL_TOEVALLIGE_VERGOEDINGEN_KEY);
        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_30_KOSTEN_TV, BEDRIJFSVOORHEFFING_ACHTERSTAL_TOEVALLIGE_VERGOEDINGEN_KEY);

        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_10_OPZEG, BEDRIJFSVOORHEFFING_ACHTERSTAL_OPZEG_VERGOEDING_KEY);

        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_13_TIJDELIJKE_WERKLOOSHEID, BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_WERKLOOSHEID_KEY);

        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_18_INSTAP_BV, BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY);
        ACHTERSTAL_REGIME_TO_BV_KEY_MAP.put(LnedefRegBv.VD_BV_18_UITTREDING_MANDATARIS, BEDRIJFSVOORHEFFING_ACHTERSTAL_UITTREDING_MANDATARIS_KEY);
