    public static RekenBvKey achterstalRegimeToSingleBvKey(LnedefRegBv regimeBv) {
        return ACHTERSTAL_REGIME_TO_BV_KEY_MAP.get(regimeBv);
    }

    public static Set<RekenBvKey> achterstalRegimeToBvKey(LnedefRegBv regimeBv) {
        RekenBvKey bvKey = ACHTERSTAL_REGIME_TO_BV_KEY_MAP.get(regimeBv);
        Set<RekenBvKey> bvKeys = new HashSet<>();
        if (bvKey != null) {
            bvKeys.add(bvKey);
        }
        return bvKeys;
    }

    public static boolean isAchterstalRegimeBv(LnedefRegBv regimeBv, RekenBvKey bvKey) {
        RekenBvKey key = ACHTERSTAL_REGIME_TO_BV_KEY_MAP.get(regimeBv);
        return key == bvKey;
    }

    public static RekenBvKey bedragTypeToRekenBvKey(RekenBedragType type, LnedefRegBv regimeBv, LocalDate rekenDatum) {
        RekenBvKey key;
        switch (type) {
