    public static MoneyKey regimeToSubBvKey(LnedefRegBv regimeBv, LocalDate datum) {
        Map<LnedefRegBv, RekenBvSubKey> regimeToSubBvKey = new HashMap<>();
        for (LnedefRegBv regime : REGIMES_GEWONE_BV_NORM) {
            regimeToSubBvKey.put(regime, RekenBvSubKey.BV_GEWONE_BEZOLDIGING_NORM_KEY);
        }

        if (datum.compareTo(BvTools.START_OVERWERK_GEWONE_BEZOLDIGING) >= 0) {
            regimeToSubBvKey.put(LnedefRegBv.VD_BV_10_OVERWERK, RekenBvSubKey.BV_GEWONE_BEZOLDIGING_NORM_KEY);
        } else {
            regimeToSubBvKey.put(LnedefRegBv.VD_BV_10_OVERWERK, RekenBvSubKey.BV_EXCEPTIONEEL_NORM_KEY);
        }

        for (LnedefRegBv regime : REGIMES_GEWONE_BV_PENS) {
            regimeToSubBvKey.put(regime, RekenBvSubKey.BV_GEWONE_BEZOLDIGING_PENS_KEY);
        }

        if (datum.getYear() < BvTools.STARTJAAR_FICHE_281_18) {
            for (LnedefRegBv regime : REGIMES_GEWONE_BV_ZIV) {
                regimeToSubBvKey.put(regime, RekenBvSubKey.BV_GEWONE_BEZOLDIGING_NORM_KEY);
            }
        } else {
            for (LnedefRegBv regime : REGIMES_GEWONE_BV_ZIV) {
                regimeToSubBvKey.put(regime, RekenBvSubKey.BV_GEWONE_BEZOLDIGING_ZIV_KEY);
            }
        }
        regimeToSubBvKey.put(LnedefRegBv.VD_BV_20_VEREFFENAAR, RekenBvSubKey.BV_VEREFFENAAR_KEY);
        regimeToSubBvKey.put(LnedefRegBv.VD_BV_17_BRUG_PENS, RekenBvSubKey.BV_BRUG_PENSIOEN_KEY);

        regimeToSubBvKey.put(LnedefRegBv.VD_BV_10_BZ___EXC, RekenBvSubKey.BV_EXCEPTIONEEL_NORM_KEY);
        regimeToSubBvKey.put(LnedefRegBv.VD_BV_14_B_AU_EXC, RekenBvSubKey.BV_EXCEPTIONEEL_BAO_KEY);
        regimeToSubBvKey.put(LnedefRegBv.VD_BV_16_RENTE_EXC, RekenBvSubKey.BV_EXCEPTIONEEL_BO_KEY);

        regimeToSubBvKey.put(LnedefRegBv.VD_BV_10_BZ___TV, RekenBvSubKey.BV_TOEVALLIGE_VERGOEDINGEN_NORM_KEY);
        regimeToSubBvKey.put(LnedefRegBv.VD_BV_30_BBI__TV, RekenBvSubKey.BV_TOEVALLIGE_VERGOEDINGEN_BBI_KEY);
        regimeToSubBvKey.put(LnedefRegBv.VD_BV_30_KOSTEN_TV, RekenBvSubKey.BV_TOEVALLIGE_VERGOEDINGEN_BBI_KEY);

        MoneyKey bvKey = BvTools.regimeToSingleBvKey(regimeBv, datum);
        if (bvKey == RekenBvKey.BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY || bvKey == BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY
                || bvKey == BEDRIJFSVOORHEFFING_TOEVALLIGE_VERGOEDINGEN_KEY) {
            bvKey = regimeToSubBvKey.get(regimeBv);
        }

        return bvKey;
    }

